const message = $json.body?.message ?? $json.message ?? {};
const eventType = message.type ?? 'unknown';
const clean = (value, max) => String(value ?? '').replace(/[\u0000-\u001f\u007f]/g, ' ').replace(/\s+/g, ' ').trim().slice(0, max);
const parseParameters = (value) => {
  if (typeof value !== 'string') return value ?? {};
  try { return JSON.parse(value); } catch { return {}; }
};
const scoreLead = (lead = {}) => {
  if (lead.consentToContact !== true) return { score: 0, tier: 'do-not-contact', lead };
  let score = 0;
  if (lead.email || lead.phone) score += 10;
  if (lead.serviceType) score += 10;
  if (lead.decisionMaker === true) score += 15;
  const days = Number(lead.timelineDays);
  if (Number.isFinite(days) && days <= 30) score += 20; else if (Number.isFinite(days) && days <= 90) score += 15;
  const budget = Number(lead.budget);
  if (budget >= 2500) score += 25; else if (budget >= 1000) score += 15;
  const size = Number(lead.officeSize);
  if (size >= 20) score += 20; else if (size >= 5) score += 10;
  return { score, tier: score >= 90 ? 'hot' : score >= 50 ? 'warm' : 'nurture', lead };
};
const buildCalendarRequest = (input = {}, toolCallId = '') => {
  if (input.explicitSchedulingConsent !== true) return { created: false, ready: false, blocked: true, reason: 'No explicit consent to create a calendar request' };
  const attendeeEmail = clean(input.attendeeEmail, 254).toLowerCase();
  const startsAt = clean(input.startsAt, 64);
  const durationMinutes = Number(input.durationMinutes);
  const timeZone = clean(input.timeZone, 64);
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(attendeeEmail)) return { created: false, ready: false, blocked: true, reason: 'A valid attendee email is required' };
  if (!Number.isFinite(Date.parse(startsAt))) return { created: false, ready: false, blocked: true, reason: 'A valid start time is required' };
  if (!Number.isInteger(durationMinutes) || durationMinutes < 15 || durationMinutes > 120) return { created: false, ready: false, blocked: true, reason: 'Duration must be an integer from 15 to 120 minutes' };
  try { new Intl.DateTimeFormat('en-US', { timeZone }).format(); } catch { return { created: false, ready: false, blocked: true, reason: 'A valid IANA time zone is required' }; }
  const request = { attendeeEmail, startsAt: new Date(startsAt).toISOString(), durationMinutes, timeZone, title: clean(input.title, 80) || 'Qualified lead follow-up', notes: clean(input.notes, 500), idempotencyKey: `vapi-calendar:${clean(toolCallId, 128) || [attendeeEmail, startsAt, durationMinutes, timeZone].join(':')}` };
  return { created: false, ready: true, blocked: false, request, note: 'Reference workflow only; no live calendar API is called' };
};
if (eventType === 'tool-calls') {
  const outcomes = (message.toolCallList ?? []).map(call => {
    const name = call.name ?? call.function?.name ?? '';
    const parameters = parseParameters(call.parameters ?? call.function?.arguments);
    const outcome = name === 'buildCalendarRequest' ? buildCalendarRequest(parameters, call.id) : scoreLead(parameters);
    return { name, toolCallId: call.id, outcome };
  });
  const calendarOutcome = outcomes.find(item => item.name === 'buildCalendarRequest' && item.outcome.ready === true)?.outcome;
  const results = outcomes.map(item => ({ name: item.name, toolCallId: item.toolCallId, result: JSON.stringify(item.outcome) }));
  return [{ json: { forwardToCrm: false, calendarRequestReady: Boolean(calendarOutcome), calendarRequest: calendarOutcome?.request ?? null, responseBody: { results } } }];
}
if (eventType === 'end-of-call-report') {
  const qualification = scoreLead(message.analysis?.structuredData ?? {});
  const crmRecord = { callId: message.call?.id ?? '', occurredAt: message.endedAt ?? new Date().toISOString(), endedReason: message.endedReason ?? 'unknown', recordingConsentGranted: Boolean(message.compliance?.recordingConsent?.grantedAt), qualification };
  return [{ json: { forwardToCrm: qualification.lead.consentToContact === true, calendarRequestReady: false, crmRecord, responseBody: { accepted: true } } }];
}
return [{ json: { forwardToCrm: false, calendarRequestReady: false, responseBody: { accepted: true, ignored: eventType } } }];
